import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { API } from "../api/base";
import "./CompanyWallet.scss";

export default function CompanyWallet() {
  const [wallet, setWallet] = useState({
    walletBalance: 0,
    totalPaid: 0,
    transactions: []   // ✅ SAFE DEFAULT
  });

  const [loading, setLoading] = useState(true);

  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    document.body.classList.add("company-theme");

    const fetchWallet = async () => {
      try {
        const res = await fetch(`${API}/api/company/wallet`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        const data = await res.json();

        // ✅ Defensive fallback
        setWallet({
          walletBalance: data.walletBalance || 0,
          totalPaid: data.totalPaid || 0,
          transactions: data.transactions || []
        });

      } catch (err) {
        console.error("Wallet fetch error:", err);
      } finally {
        setLoading(false);
      }
    };

    fetchWallet();

    return () => {
      document.body.classList.remove("company-theme");
    };
  }, [token]);

  if (loading) return <div className="company-page">Loading...</div>;

  return (
    <div className="company-page">

      <div className="top-bar">
        <button className="back-btn" onClick={() => navigate("/company")}>
          ⬅ Back
        </button>
        <h1>Company Wallet</h1>
      </div>

      {/* =========================
         WALLET SUMMARY
      ========================= */}
      <div className="wallet-summary">
        <div className="stat-box">
          <h3>Current Balance</h3>
          <p>₹{wallet.walletBalance}</p>
        </div>

        <div className="stat-box">
          <h3>Total Paid</h3>
          <p>₹{wallet.totalPaid}</p>
        </div>
      </div>

      {/* =========================
         TRANSACTIONS
      ========================= */}
      <div className="transactions">
        <h2>Transaction History</h2>

        {wallet.transactions.length === 0 ? (
          <p>No transactions yet.</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Bug</th>
                <th>Hacker</th>
                <th>Amount</th>
                <th>Date</th>
              </tr>
            </thead>
            <tbody>
              {wallet.transactions.map((t) => (
                <tr key={t._id}>
                  <td>{t.bug?.title || "-"}</td>
                  <td>{t.hacker?.name || t.hacker?.email || "-"}</td>
                  <td>₹{t.amount}</td>
                  <td>
                    {t.createdAt
                      ? new Date(t.createdAt).toLocaleDateString()
                      : "-"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

    </div>
  );
}
